var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관 본부</color> 라운드 테이블","JPN":"<color=#ffd34c>プリドウェン機関本部</color>ラウンドテーブル","ENG":"<color=#ffd34c>Prydwen Institution HQ</color> Round Table","TWN":"<color=#ffd34c>普利多溫機關總部</color> 圓桌會議","SCN":"<color=#ffd34c>普利多温机关总部</color> 圆桌会议","DEU":"<color=#ffd34c>Prydwen Institution HQ</color> Round Table","FRA":"<color=#ffd34c>Prydwen Institution HQ</color> Round Table"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"기관장님! LAKE-9에 침입한 학회원을 모두 제압 완료하였습니다!","JPN":"機関長！　LAKE-9に侵入した学会員を全員制圧しました！","ENG":"Chief! We subdued all Society members that invaded LAKE-9!","TWN":"機關長！侵入LAKE-9的學會成員已全部制服！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"LAKE-2도 제압 완료하였습니다!","JPN":"LAKE-2も制圧完了です！","ENG":"LAKE-2 is complete as well!","TWN":"LAKE-2也制服完畢！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"다들 수고하셨어요.","JPN":"皆さん、お疲れさまでした。","ENG":"Good work, everyone.","TWN":"你們辛苦了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"학회에게 습격받은 시설 일곱 곳 중에서 이제 남은 건 LAKE-4, LAKE-7, LAKE-11.","JPN":"学会から襲撃された施設7カ所のうち、残ったのはLAKE-4、LAKE-7、LAKE-11。","ENG":"Out of the seven facilities that the Society ambushed, LAKE-4, LAKE-7, and LAKE-11 are still in battle.","TWN":"學會襲擊的七個設施中，現在剩下的是LAKE-4，LAKE-7，LAKE-11。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"세 곳이군요.","JPN":"3カ所ですわね。","ENG":"Three facilities.","TWN":"這三個地方。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"기관장님. 선택하셔야 합니다.","JPN":"機関長。今こそ決断を下す時です。","ENG":"Chief, you must make a decision.","TWN":"機關長，你需要抉擇。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"카운터 요원들이 빠진 지금, 남은 봉인 시설을 전부 보호하는 것은 무리입니다.","JPN":"カウンターがいない今、残りの封印施設をすべて保護することは不可能です。","ENG":"Without the Counter agents, we won't be able to protect all the remaining quarantine facilities.","TWN":"制裁者特工們如今不在，想要保護剩下的所有封印設施未免太勉強了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"LAKE-4의 경우, 지난 학회의 공격에서 받은 피해를 아직 완전히 수복하지 못했습니다.","JPN":"LAKE-4の場合、この前の学会の攻撃で受けた被害をまだ完全に修復できていません。","ENG":"In the case of LAKE-4, they haven't fully recovered from the last attack from the Society.","TWN":"而且LAKE-4，尚未完全恢復上次學會攻擊後受到的損失。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"봉인된 파편 역시 학회와 엘리시움 연합으로 인해 상당히 소모되었죠.","JPN":"封印された破片もまた、学会とエリシウム連合のせいで相当数を消耗しました。","ENG":"The sealed Fragment was consumed quite a bit because of the alliance between the Society and Elysium.","TWN":"封印的碎片也因學會和愛樂組織的聯手消耗了很多。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"다른 봉인 시설에 비해 전략적 가치가 떨어집니다.","JPN":"他の封印施設に比べ、戦略的な価値は低いです。","ENG":"Its strategic value is less than the other quarantine facilities.","TWN":"與其他封印設施相比，戰略價值較低。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"이번에야 말로, LAKE-4에 붕괴 조치를 취하자는 뜻이로군요.","JPN":"今度こそ、LAKE-4を崩壊措置しようという話ですね？","ENG":"You wish to have LAKE-4 destroyed with this opportunity.","TWN":"你的意思是，趁這次機會對LAKE-4採取瓦解措施。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"시간이 없습니다!","JPN":"時間がありません！","ENG":"We don't have time!","TWN":"沒時間了！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"녀석들에게 파편을 빼앗길 바에야, 파편과 함께 생매장시키는 편이 낫지 않습니까?","JPN":"やつらに破片を奪われるくらいなら、破片ごと生き埋めにした方がいいのでは？","ENG":"Isn't it better to bury them alive with the Fragment rather than for them to seize it?","TWN":"與其被他們搶走碎片，還不如把他們和碎片一起埋到地下！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"그곳의 기관원들도 기꺼이 희생을 감수할 것입니다.","JPN":"あそこの機関員も、喜んで犠牲を受け入れるでしょう。","ENG":"I'm sure the members there will be glad to offer their lives for the cause.","TWN":"那裡的機關成員也甘願犧牲。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"부디 용단을 내려주십시오, 기관장님!","JPN":"どうかご英断を、機関長！","ENG":"I hope you make the right decision, Chief!","TWN":"務請決斷，機關長！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"최고등급 재난경보, 고고학부장의 탈옥, 봉인 시설의 습격…….","JPN":"最高ランクの災難警報、考古学部長の脱獄、封印施設の襲撃……","ENG":"The highest-level disaster alert, the Dean of Archeology breaking out, and the ambush on the quarantine facilities...","TWN":"最高級別的災難警報，考古學教授的越獄，封印設施的襲擊……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"클리포트 게임이 끝난 지 얼마 지나지 않았는데, 기관에는 악재가 겹치는군요.","JPN":"クリフォトゲームが終わって間もないのに、機関には厄災が耐えませんわ。","ENG":"It hasn't been that long since the Qliphoth Game ended, but the Institution is experiencing one bad luck after another.","TWN":"逆卡巴拉遊戲才結束沒多久，機關就接二連三地出現危機。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"그럼에도 선택을 피해서는 안 되겠죠.","JPN":"それでも、選択は避けられません。","ENG":"But still, I cannot avoid making a decision.","TWN":"即便如此，我們也不能回避選擇。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"LAKE-4에 있는 전 인원에게 퇴거 조치 명령을 내리세요!","JPN":"LAKE-4にいるすべての人員に、退去措置命令を出しなさい！","ENG":"Instruct all members at LAKE-4 to evacuate!","TWN":"請向LAKE-4的所有人員下達撤退命令！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리드웬 기관</color> 비밀 격리 시설 LAKE-4","JPN":"<color=#ffd34c>プリドウェン機関</color>の秘密隔離施設 LAKE-4","ENG":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4","TWN":"<color=#ffd34c>普利多溫機關</color> 秘密隔離設施LAKE-4","SCN":"<color=#ffd34c>普利多温机关</color> 秘密隔离设施LAKE-4","DEU":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4","FRA":"<color=#ffd34c>Prydwen Institution</color> Secret Quarantine Facility LAKE-4"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};